#!/usr/bin/perl -w
use CGI;
use warnings;
use strict;
use Carp;

# Get the URL to redirect to from the parameter 'next'.
my $next = shift @ARGV || "index.html";

# Print out a header telling the browser that you're sending them to an
# external site and that it should go there.
print qq{Location: $next\n\n};

# And then exit, without outputting anything else.
exit 0;

